import{_ as s,c as t,o as a,a5 as o}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.16.0 (2026-05-20)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/v3.16.0.md","filePath":"guide/changelog/v3.16.0.md"}'),i={name:"guide/changelog/v3.16.0.md"};function n(r,e,d,c,l,h){return a(),t("div",null,e[0]||(e[0]=[o('<h1 id="changelog-v3-16-0-2026-05-20" tabindex="-1">Changelog v3.16.0 (2026-05-20) <a class="header-anchor" href="#changelog-v3-16-0-2026-05-20" aria-label="Permalink to &quot;Changelog v3.16.0 (2026-05-20)&quot;">​</a></h1><h2 id="version-3-16-0-2026-05-20" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.16.0" target="_blank" rel="noreferrer">3.16.0</a> (2026-05-20) <a class="header-anchor" href="#version-3-16-0-2026-05-20" aria-label="Permalink to &quot;Version [3.16.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.16.0) (2026-05-20)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.15.2...3.16.0" target="_blank" rel="noreferrer">Full Changelog</a></p><p>Minor release fixing a long-standing class of bugs in the JSON-to-parameter parsers for the <code>timestamp</code>, <code>timestamptz</code>, <code>time</code>, and <code>timetz</code> PostgreSQL types: the parsers were silently shifting incoming values by the host process&#39;s UTC offset. Bumped to minor (not patch) because the corrected behavior changes how naive ISO strings (no <code>Z</code>, no offset) are interpreted on non-UTC hosts — see <em>Breaking change</em> below. The shift was invisible on UTC hosts (the default for <code>mcr.microsoft.com/dotnet/aspnet</code> and almost every Linux container) and only surfaced once the same image ran somewhere with <code>TZ</code> set to anything else — a Windows dev box, a Kubernetes pod with <code>TZ</code> overridden, or a non-UTC CI runner — at which point stored values diverged from the JSON the caller sent by the host&#39;s offset.</p><h2 id="fix-datetime-parsers-are-now-host-tz-independent" tabindex="-1">Fix: datetime parsers are now host-TZ-independent <a class="header-anchor" href="#fix-datetime-parsers-are-now-host-tz-independent" aria-label="Permalink to &quot;Fix: datetime parsers are now host-TZ-independent&quot;">​</a></h2><p><code>TryParseTimestamp</code>, <code>TryParseTimestampTz</code>, <code>TryParseTime</code>, and <code>TryParseTimeTz</code> in <code>NpgsqlRest/ParameterParsers.cs</code> all relied on the parameter-less <code>DateTime.TryParse(value)</code> overload. That overload&#39;s default <code>DateTimeStyles.None</code> converts offset-bearing strings to the host&#39;s local TZ and tags the result <code>Kind=Local</code>. The two <code>*Tz</code> parsers then called <code>DateTime.SpecifyKind(v, DateTimeKind.Utc)</code> on the local-shifted value — but <code>SpecifyKind</code> only relabels the kind, it does not convert. The result was a host-local wall-clock value labelled UTC, written to Postgres with a silent shift.</p><p>The <code>timestamp</code> and <code>time</code> parsers used the same buggy parse and sent the local-shifted value directly to Npgsql, which transmits the wall-clock verbatim for a <code>without time zone</code> column — the same silent shift, same size as the host&#39;s offset.</p><p>All four parsers now use:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">DateTime</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">TryParse</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span></span>\n<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    value</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>\n<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    CultureInfo</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">InvariantCulture</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>\n<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    DateTimeStyles</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">AssumeUniversal </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">|</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> DateTimeStyles</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">AdjustToUniversal</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>\n<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">    out</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> var</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> v</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><ul><li><code>AssumeUniversal</code> treats naive ISO strings (no <code>Z</code>, no offset) as UTC — the canonical JSON-over-HTTP convention.</li><li><code>AdjustToUniversal</code> converts any <code>Z</code>-bearing or offset-bearing value to UTC.</li></ul><p>The result is a <code>DateTime</code> with <code>Kind=Utc</code> carrying the true UTC instant regardless of the host&#39;s TZ. The <code>*Tz</code> parsers use it directly. The <code>without time zone</code> parsers strip the kind back to <code>Unspecified</code> so Npgsql sends the UTC clock-time as the naive wall-clock value, matching the column semantics.</p><h2 id="why-this-was-hidden-so-long" tabindex="-1">Why this was hidden so long <a class="header-anchor" href="#why-this-was-hidden-so-long" aria-label="Permalink to &quot;Why this was hidden so long&quot;">​</a></h2><p>Almost every production container runs <code>TZ=UTC</code> by default. On a UTC host, <code>DateTime.TryParse(...)</code>&#39;s local-conversion is a no-op and the <code>SpecifyKind(Utc)</code> &quot;lie&quot; coincidentally matches reality. The bug only manifests once the same code is deployed where <code>TZ</code> is anything else. The first symptom is usually a downstream report along the lines of &quot;we send <code>2026-05-20T06:00:00Z</code> and Postgres stored <code>08:00</code>&quot; — which is exactly the host&#39;s UTC offset.</p><p>The existing <code>MultiParamsTests2</code> / <code>MultiParamsQueryStringTests2</code> test pairs already hinted at this — both used <code>Should().Match(t =&gt; t == &quot;12:06:59...&quot; || t == &quot;11:06:59...&quot;)</code> style assertions with a comment that read <em>&quot;integration server seems to have a different datetime alltogether&quot;</em>. That was the bug, papered over. After this fix both tests assert single deterministic values.</p><h2 id="tryparsedate-left-alone" tabindex="-1"><code>TryParseDate</code> left alone <a class="header-anchor" href="#tryparsedate-left-alone" aria-label="Permalink to &quot;`TryParseDate` left alone&quot;">​</a></h2><p><code>DateOnly.TryParse</code> rejects <code>Z</code>- and offset-bearing strings outright (verified across <code>UTC</code>, <code>America/Los_Angeles</code>, <code>Europe/Zagreb</code>, <code>Pacific/Auckland</code>) — it does not silently shift, so the <code>date</code> parser was not affected by the host-TZ bug class. It was however a separate papercut: callers sending full ISO timestamps (e.g. <code>&quot;2026-05-20T03:00:00Z&quot;</code>) to a <code>date</code> column got a flat parse failure. <code>TryParseDate</code> now falls back to a <code>DateTime</code> parse and extracts the date portion when <code>DateOnly.TryParse</code> rejects the input, honoring the same <code>JsonTimestampsAreUtc</code> semantic as the other datetime parsers (UTC date when the flag is true, host-local date when false).</p><h2 id="breaking-change" tabindex="-1">Breaking change <a class="header-anchor" href="#breaking-change" aria-label="Permalink to &quot;Breaking change&quot;">​</a></h2><p>JSON timestamps are now interpreted as <strong>UTC</strong>:</p><ul><li><code>Z</code>-suffixed and offset-bearing ISO strings are converted to UTC.</li><li>Naive ISO strings (no offset, no <code>Z</code>) are <strong>assumed UTC</strong> rather than interpreted as host-local time.</li></ul><p>Callers who relied on the previous &quot;JSON is host-local&quot; behavior — usually by accident, because the host happened to be UTC — will see no change. Callers who sent <code>Z</code> strings expecting UTC were silently broken on non-UTC hosts and are now correct.</p><h2 id="opt-out-npgsqlrestoptions-jsontimestampsareutc" tabindex="-1">Opt-out: <code>NpgsqlRestOptions.JsonTimestampsAreUtc</code> <a class="header-anchor" href="#opt-out-npgsqlrestoptions-jsontimestampsareutc" aria-label="Permalink to &quot;Opt-out: `NpgsqlRestOptions.JsonTimestampsAreUtc`&quot;">​</a></h2><p>Users whose downstream code genuinely depends on the legacy &quot;naive timestamps are host-local&quot; behavior — and who cannot update those callers to send <code>Z</code>-suffixed values — can restore the pre-3.16.0 behavior by setting <code>JsonTimestampsAreUtc</code> to <code>false</code>:</p><ul><li><strong>Library:</strong> <code>new NpgsqlRestOptions { JsonTimestampsAreUtc = false, ... }</code>.</li><li><strong>Client (<code>appsettings.json</code>):</strong> <code>&quot;NpgsqlRest&quot;: { &quot;JsonTimestampsAreUtc&quot;: false }</code> (default is <code>true</code>).</li></ul><p>When false, the four parsers fall back to the bare <code>DateTime.TryParse(value)</code> overload — <code>Z</code>/offset strings get host-local-converted and tagged <code>Kind=Local</code>, naive strings get parsed as <code>Kind=Unspecified</code>, and the <code>*Tz</code> parsers re-apply <code>SpecifyKind(Utc)</code> on top. That reproduces the exact pre-3.16.0 code path. Note that this is <strong>not recommended</strong> for new deployments: it puts you back in the bug class the rest of this release fixes. The flag exists purely as a compatibility escape hatch.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><p>New file <code>NpgsqlRestTests/HostTimeZoneIndependenceTests.cs</code> covers all four parsers via echo functions and <code>json_build_object</code> round-trips:</p><ul><li><code>timestamptz</code> with <code>Z</code> suffix, with numeric offset, and naive (assumed UTC)</li><li><code>timestamp</code> with <code>Z</code> suffix (stored as naive UTC clock-time)</li><li><code>timetz</code> with <code>Z</code> suffix (round-trips as UTC)</li><li><code>time</code> with <code>Z</code> suffix (UTC clock-time extracted)</li></ul><p>Each assertion is exact — no host-TZ-tolerant ORs. The fixture forces the database to UTC at creation (<code>alter database … set timezone to &#39;UTC&#39;</code>), so the assertions stay deterministic across runners. To verify host-TZ independence at the parser layer, run the suite under a non-UTC <code>TZ</code> env var (<code>TZ=America/Los_Angeles dotnet test</code>, for example) — the tests must still pass.</p><p>The two existing <code>MultiParams*</code> tests had their loose <code>Should().Match(...)</code> assertions for <code>timestamptz</code> and <code>timetz</code> replaced with single-value <code>Should().Be(...)</code> assertions, now that the parsers produce deterministic output.</p><h2 id="files-touched" tabindex="-1">Files touched <a class="header-anchor" href="#files-touched" aria-label="Permalink to &quot;Files touched&quot;">​</a></h2><ul><li><code>NpgsqlRest/ParameterParsers.cs</code> — four parsers switched to <code>AssumeUniversal | AdjustToUniversal</code>.</li><li><code>NpgsqlRestTests/HostTimeZoneIndependenceTests.cs</code> — new, six tests covering the four type variants.</li><li><code>NpgsqlRestTests/ParamTests/MultiParamsTests2.cs</code> — tightened <code>timestamptz</code> / <code>timetz</code> assertions.</li><li><code>NpgsqlRestTests/ParamTests/MultiParamsQueryStringTests2.cs</code> — same.</li></ul><p>No config changes, no API surface changes.</p>',32)]))}const m=s(i,[["render",n]]);export{u as __pageData,m as default};
